packageRules.autoReplaceStringTemplate:
procedure {{{procedureName}}};
begin
  // https://dotnet.microsoft.com/download/dotnet/{{{packageName}}}
  if not Dependency_IsNetCoreInstalled('{{{runtimeName}}}', {{{newMajor}}}, {{{newMinor}}}, {{{newPatch}}}) then begin
    Dependency_Add('{{{archiveName}}}' + Dependency_ArchSuffix + '.exe',
      '/lcid ' + IntToStr(GetUILanguage) + ' /passive /norestart',
      '{{{displayNamePrefix}}}{{{newValue}}}' + Dependency_ArchTitle,
      Dependency_String('https://builds.dotnet.microsoft.com/dotnet/{{{downloadPath}}}/{{{newValue}}}/{{{binaryNamePrefix}}}-{{{newValue}}}-win-x86.exe', 'https://builds.dotnet.microsoft.com/dotnet/{{{downloadPath}}}/{{{newValue}}}/{{{binaryNamePrefix}}}-{{{newValue}}}-win-x64.exe', 'https://builds.dotnet.microsoft.com/dotnet/{{{downloadPath}}}/{{{newValue}}}/{{{binaryNamePrefix}}}-{{{newValue}}}-win-arm64.exe'),
      '', False, False);
  end;
end;
